import { createClient } from "@liveblocks/client";
import { createRoomContext } from "@liveblocks/react";

const client = createClient({
  authEndpoint: "/api/liveblocks-auth",
});

export type Presence = {
  color: string;
};

type Storage = Record<string, never>;
type UserMeta = Record<string, never>;
type RoomEvent = never;

export const {
  RoomProvider,
  useMyPresence,
  useUpdateMyPresence,
  useOthers,
  useSelf,
} = createRoomContext<Presence, Storage, UserMeta, RoomEvent>(client);

import { Liveblocks } from "@liveblocks/node";
import { NextRequest } from "next/server";

const liveblocks = new Liveblocks({
  secret: process.env.LIVEBLOCKS_SECRET_KEY!,
});

export async function POST(request: NextRequest) {
  // Create a session for the current user
  const session = liveblocks.prepareSession(`user-${Math.random().toString(36).slice(2)}`, {
    userInfo: {},
  });

  const roomId = `color-picker-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;
  session.allow(roomId, session.FULL_ACCESS);

  const { status, body } = await session.authorize();
  return new Response(body, { status });
}

"use client";

import { ReactNode } from "react";
import { RoomProvider } from "../liveblocks.config";

const roomId = `color-picker-${process.env.NEXT_PUBLIC_ZEALT_RUN_ID}`;

export function Room({ children }: { children: ReactNode }) {
  return (
    <RoomProvider
      id={roomId}
      initialPresence={{ color: "#000000" }}
    >
      {children}
    </RoomProvider>
  );
}

"use client";

import { useMyPresence, useOthers, useSelf } from "../liveblocks.config";

export function ColorPicker() {
  const [myPresence, updateMyPresence] = useMyPresence();
  const others = useOthers();
  const self = useSelf();

  // Build the full list: current user + all others
  const allUsers: Array<{ connectionId: number; color: string }> = [];

  if (self) {
    allUsers.push({
      connectionId: self.connectionId,
      color: myPresence.color ?? "#000000",
    });
  }

  for (const other of others) {
    if (other.presence?.color) {
      allUsers.push({
        connectionId: other.connectionId,
        color: other.presence.color,
      });
    }
  }

  return (
    <div>
      <input
        id="color-input"
        type="color"
        value={myPresence.color ?? "#000000"}
        onChange={(e) => {
          updateMyPresence({ color: e.target.value });
        }}
      />
      <ul id="user-colors">
        {allUsers.map(({ connectionId, color }) => (
          <li
            key={connectionId}
            data-connection-id={connectionId}
            data-color={color}
            style={{ backgroundColor: color, width: 40, height: 40, listStyle: "none" }}
          />
        ))}
      </ul>
    </div>
  );
}

import { Room } from "./Room";
import { ColorPicker } from "./ColorPicker";

export default function Page() {
  return (
    <Room>
      <ColorPicker />
    </Room>
  );
}

